244	  }
245	  const incoming = parseTelegramTopicConversation({
246	    conversationId: params.conversationId,
247	    parentConversationId: params.parentConversationId,
248	  });
249	  if (!incoming || !incoming.chatId.startsWith("-")) {
250	    return null;
251	  }
