361	async function resolveTelegramTargets(params: {
362	  cfg: OpenClawConfig;
363	  accountId?: string | null;
364	  inputs: string[];
365	  kind: "user" | "group";
366	}) {
367	  if (params.kind !== "user") {
368	    return params.inputs.map((input) => ({
369	      input,
370	      resolved: false as const,
371	      note: "Telegram runtime target resolution only supports usernames for direct-message lookups.",
372	    }));
373	  }
374	  const account = resolveTelegramAccount({
375	    cfg: params.cfg,
376	    accountId: params.accountId,
377	  });
378	  const token = account.token.trim();
379	  if (!token) {
380	    return params.inputs.map((input) => ({
381	      input,
382	      resolved: false as const,
383	      note: "Telegram bot token is required to resolve @username targets.",
384	    }));
385	  }
386	  return await Promise.all(
387	    params.inputs.map(async (input) => {
388	      const trimmed = input.trim();
389	      if (!trimmed) {
390	        return {
391	          input,
392	          resolved: false as const,
393	          note: "Telegram target is required.",
394	        };
395	      }
396	      const normalized = trimmed.startsWith("@") ? trimmed : `@${trimmed}`;
397	      try {
398	        const id = await lookupTelegramChatId({
399	          token,
400	          chatId: normalized,
401	          network: account.config.network,
402	        });
403	        if (!id) {
404	          return {
405	            input,
406	            resolved: false as const,
407	            note: "Telegram username could not be resolved by the configured bot.",
408	          };
409	        }
410	        return {
411	          input,
412	          resolved: true as const,
413	          id,
414	          name: normalized,
415	        };
416	      } catch (error) {
417	        return {
418	          input,
419	          resolved: false as const,
420	          note: error instanceof Error ? error.message : String(error),
421	        };
422	      }
423	    }),
424	  );
425	}
