### 5. `extensions/pulseboard/src/channel.ts`

The main plugin built with `createChatChannelPlugin`. All adapters are stubs or minimal inline objects.

Key decisions based on codebase research:
- **`outbound`**: Uses the "direct" shape (like Nostr) — top-level `deliveryMode`, `textChunkLimit`, and `sendText` — rather than the "attached results" shape (IRC). `sendText` returns `attachChannelToResult("pulseboard", { to, messageId })`.
- **`config`**: Minimal inline adapter with stub `listAccountIds`, `resolveDefaultAccountId`, `resolveAccount`.
- **`setup`**: Inline object with stub `applyAccountConfig`.
- **`gateway`**: Inline object with async `startAccount` that logs and returns `{ stop: async () => {} }`.
- **`messaging`**: Inline object; `normalizeTarget` trims whitespace.
- **`meta`**: Built via `getChatChannelMeta({ label, docsPath, blurb })`.

```typescript
import type { ChannelPlugin } from "openclaw/plugin-sdk/core";
import {
  attachChannelToResult,
  createChatChannelPlugin,
  getChatChannelMeta,
} from "openclaw/plugin-sdk/core";

export const pulseBoardPlugin: ChannelPlugin = createChatChannelPlugin({
  base: {
    id: "pulseboard",
    meta: getChatChannelMeta({
      label: "PulseBoard",
      docsPath: "/channels/pulseboard",
      blurb: "Connect to PulseBoard bulletin board messaging.",
    }),
    capabilities: {
      chatTypes: ["direct", "group"],
      media: false,
    },
    reload: {
      configPrefixes: ["channels.pulseboard"],
    },
    config: {
      listAccountIds: () => [],
      resolveDefaultAccountId: () => "default",
      resolveAccount: (_cfg, accountId) => ({ accountId: accountId ?? "default" }),
    },
    setup: {
      applyAccountConfig: async () => {},
    },
    gateway: {
      startAccount: async ({ accountId }) => {
        console.log(`[pulseboard] Starting account: ${accountId}`);
        return { stop: async () => {} };
      },
    },
    messaging: {
      normalizeTarget: (target: string) => target.trim(),
    },
  },
  outbound: {
    deliveryMode: "direct",
    textChunkLimit: 4000,
    sendText: async ({ to, accountId }) => {
      return attachChannelToResult("pulseboard", {
        to,
        messageId: `pulseboard-${Date.now()}`,
      });
    },
  },
});
```

